    78→        </div>
    79→
    80→        <div class="form-group" style="margin-bottom:1rem;">
    81→          <label style="display:block;font-size:13px;font-weight:500;margin-bottom:4px;">Password</label>
    82→          <input type="password" id="password" required minlength="6" style="width:100%;padding:10px 12px;border:1px solid var(--ink-10);border-radius:8px;font-size:14px;" placeholder="••••••••">
    83→        </div>
    84→
    85→        <div id="confirm-group" style="display:none;margin-bottom:1rem;">
    86→          <label style="display:block;font-size:13px;font-weight:500;margin-bottom:4px;">Confirm Password</label>
    87→          <input type="password" id="confirm-password" style="width:100%;padding:10px 12px;border:1px solid var(--ink-10);border-radius:8px;font-size:14px;" placeholder="••••••••">
    88→        </div>
