    90→        <div id="auth-error" style="display:none;background:var(--crimson-light);color:var(--crimson);padding:10px;border-radius:8px;margin-bottom:1rem;font-size:13px;"></div>
    91→        <div id="auth-success" style="display:none;background:var(--emerald-light);color:var(--emerald);padding:10px;border-radius:8px;margin-bottom:1rem;font-size:13px;"></div>
    92→
    93→        <button type="submit" class="btn btn-gold" style="width:100%;" id="submit-btn">Sign In</button>
