   100→
   101→  // Tab switching
   102→  let isSignUp = false;
   103→  const tabs = container.querySelectorAll('.tab-btn');
   104→  const confirmGroup = container.querySelector('#confirm-group');
   105→  const submitBtn = container.querySelector('#submit-btn');
   106→
   107→  tabs.forEach(tab => {
   108→    tab.addEventListener('click', () => {
   109→      tabs.forEach(t => {
   110→        t.classList.remove('active');
   111→        t.style.color = 'var(--ink-60)';
   112→        t.style.borderBottomColor = 'transparent';
   113→      });
   114→      tab.classList.add('active');
   115→      tab.style.color = 'var(--ink)';
   116→      tab.style.borderBottomColor = 'var(--gold)';
   117→
   118→      isSignUp = tab.dataset.tab === 'signup';
   119→      confirmGroup.style.display = isSignUp ? 'block' : 'none';
   120→      submitBtn.textContent = isSignUp ? 'Create Account' : 'Sign In';
   121→    });
   122→  });
   123→
   124→  // Form submission
   125→  const form = container.querySelector('#auth-form');
   126→  const errorEl = container.querySelector('#auth-error');
   127→  const successEl = container.querySelector('#auth-success');
   128→
   129→  form.addEventListener('submit', async (e) => {
   130→    e.preventDefault();
   131→    errorEl.style.display = 'none';
   132→    successEl.style.display = 'none';
   133→
   134→    const email = container.querySelector('#email').value;
   135→    const password = container.querySelector('#password').value;
   136→
   137→    if (isSignUp) {
   138→      const confirmPass = container.querySelector('#confirm-password').value;
   139→      if (password !== confirmPass) {
   140→        errorEl.textContent = 'Passwords do not match';
   141→        errorEl.style.display = 'block';
   142→        return;
   143→      }
   144→    }
   145→
   146→    submitBtn.disabled = true;
   147→    submitBtn.textContent = isSignUp ? 'Creating...' : 'Signing in...';
   148→
   149→    try {
   150→      if (isSignUp) {
   151→        const result = await signUp(email, password);
   152→        if (result.error) {
   153→          throw new Error(result.error);
   154→        }
   155→        successEl.textContent = 'Account created! Check your email to confirm, then sign in.';
   156→        successEl.style.display = 'block';
   157→        submitBtn.textContent = 'Create Account';
   158→      } else {
   159→        const result = await signIn(email, password);
   160→        if (result.error) {
   161→          throw new Error(result.error);
   162→        }
   163→        // Save tokens
   164→        localStorage.setItem('access_token', result.access_token);
   165→        localStorage.setItem('refresh_token', result.refresh_token);
   166→        localStorage.setItem('user_email', result.email);
   167→        localStorage.setItem('user_id', result.user_id);
   168→
   169→        // Update auth state
   170→        AuthState.isLoggedIn = true;
   171→        AuthState.email = result.email;
   172→        AuthState.userId = result.user_id;
   173→
   174→        successEl.textContent = 'Signed in successfully! Redirecting...';
   175→        successEl.style.display = 'block';
   176→
   177→        setTimeout(() => navigateTo('dashboard'), 1000);
   178→      }
   179→    } catch (err) {
   180→      errorEl.textContent = err.message || 'Authentication failed';
   181→      errorEl.style.display = 'block';
   182→      submitBtn.textContent = isSignUp ? 'Create Account' : 'Sign In';
   183→    }
   184→
   185→    submitBtn.disabled = false;
   186→  });
   187→}
