   189→async function handleLogout() {
   190→  localStorage.removeItem('access_token');
   191→  localStorage.removeItem('refresh_token');
   192→  localStorage.removeItem('user_email');
   193→  localStorage.removeItem('user_id');
   194→
   195→  AuthState.isLoggedIn = false;
   196→  AuthState.email = null;
   197→  AuthState.userId = null;
   198→
   199→  navigateTo('auth');
   200→}
