    12→    body: JSON.stringify(body)
    13→  });
    14→  if (!res.ok) {
    15→    const err = await res.json().catch(() => ({}));
    16→    throw new Error(err.detail || `API error ${res.status}`);
    17→  }
    18→  return res.json();
    19→}
