// Forgot Password Modal
const forgotModal = container.querySelector('#forgot-modal');
const forgotPasswordLink = container.querySelector('#forgot-password-link');
const closeForgotModal = container.querySelector('#close-forgot-modal');
const forgotForm = container.querySelector('#forgot-form');
const forgotError = container.querySelector('#forgot-error');
const forgotSuccess = container.querySelector('#forgot-success');
const forgotSubmitBtn = container.querySelector('#forgot-submit-btn');

forgotPasswordLink.addEventListener('click', (e) => {
  e.preventDefault();
  forgotModal.style.display = 'flex';
  forgotError.style.display = 'none';
  forgotSuccess.style.display = 'none';
});

closeForgotModal.addEventListener('click', () => {
  forgotModal.style.display = 'none';
});

forgotModal.addEventListener('click', (e) => {
  if (e.target === forgotModal) {
    forgotModal.style.display = 'none';
  }
});

forgotForm.addEventListener('submit', async (e) => {
  e.preventDefault();
  forgotError.style.display = 'none';
  forgotSuccess.style.display = 'none';

  const email = container.querySelector('#forgot-email').value;
  forgotSubmitBtn.disabled = true;
  forgotSubmitBtn.textContent = 'Sending...';

  try {
    const result = await resetPassword(email);
    if (result.error) {
      throw new Error(result.error);
    }
    forgotSuccess.textContent = 'Password reset email sent! Check your inbox.';
    forgotSuccess.style.display = 'block';
    forgotSubmitBtn.textContent = 'Email Sent';
  } catch (err) {
    forgotError.textContent = err.message || 'Failed to send reset email';
    forgotError.style.display = 'block';
    forgotSubmitBtn.textContent = 'Send Reset Link';
  }

  forgotSubmitBtn.disabled = false;
});

async function renderAccountPage(container) {
  container.innerHTML = `
    <div class="page-hdr">
      <div class="page-title">Account</div>
      <div class="page-sub">Manage your ArthMitra account</div>
    </div>
    <div class="card" style="max-width:500px;margin:2rem auto;">
      <div style="text-align:center;margin-bottom:1.5rem;">
        <div style="width:60px;height:60px;background:var(--gold);border-radius:50%;display:flex;align-items:center;justify-content:center;margin:0 auto 1rem;font-size:24px;">
          ${AuthState.email ? AuthState.email[0].toUpperCase() : '?'}
        </div>
        <div style="font-weight:600;">${AuthState.email || 'User'}</div>
        <div style="font-size:12px;color:var(--ink-60);">Logged in</div>
      </div>

      <div id="profile-section" style="border-top:1px solid var(--ink-10);padding-top:1rem;margin-bottom:1rem;">
        <div style="font-weight:600;margin-bottom:12px;display:flex;align-items:center;gap:8px;">
          <span>📋</span> Stored Profile Data
        </div>
        <div id="profile-data" style="font-size:13px;color:var(--ink-60);">
          Loading profile...
        </div>
      </div>

      <div style="border-top:1px solid var(--ink-10);padding-top:1rem;">
        <button class="btn btn-gold" style="width:100%;margin-bottom:8px;" id="sync-btn">Sync Profile to Cloud</button>
        <button class="btn btn-ghost" style="width:100%;" id="logout-btn">Sign Out</button>
      </div>
    </div>`;

  container.querySelector('#logout-btn').addEventListener('click', handleLogout);
  container.querySelector('#sync-btn').addEventListener('click', handleSyncProfile);

  // Load and display stored profile
  try {
    const result = await getUserProfile();
    if (result.success && result.profile) {
      displayStoredProfile(container, result.profile, result.updated_at);
    } else {
      container.querySelector('#profile-data').innerHTML = `
        <div style="text-align:center;padding:1rem;background:var(--ink-05);border-radius:8px;">
          <div style="margin-bottom:8px;">No profile saved yet</div>
          <div style="font-size:12px;">Complete your profile and click "Sync Profile to Cloud"</div>
        </div>`;
    }
  } catch (err) {
    container.querySelector('#profile-data').innerHTML = `
      <div style="color:var(--crimson);">Failed to load profile: ${err.message}</div>`;
  }
}

function displayStoredProfile(container, profile, updatedAt) {
  const formatDate = (dateStr) => {
    if (!dateStr) return 'Unknown';
    const date = new Date(dateStr);
    return date.toLocaleDateString('en-IN', {
      day: 'numeric',
      month: 'short',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  const profileHtml = `
    <div style="background:var(--ink-05);border-radius:8px;padding:12px;margin-bottom:8px;">
      <div style="font-size:11px;color:var(--ink-40);margin-bottom:8px;">
        Last synced: ${formatDate(updatedAt)}
      </div>

      ${profile.name ? `
      <div style="margin-bottom:12px;">
        <div style="font-weight:600;font-size:14px;color:var(--ink);">${profile.name}</div>
        <div style="font-size:12px;color:var(--ink-60);">${profile.age || '?'} years · ${profile.city || 'Unknown city'}</div>
      </div>
      ` : ''}

      <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;">
        <div style="background:white;padding:8px;border-radius:6px;">
          <div style="font-size:10px;color:var(--ink-40);text-transform:uppercase;">Annual Income</div>
          <div style="font-weight:600;color:var(--emerald);">₹${fmt(profile.income || 0)}</div>
        </div>
        <div style="background:white;padding:8px;border-radius:6px;">
          <div style="font-size:10px;color:var(--ink-40);text-transform:uppercase;">Health Score</div>
          <div style="font-weight:600;color:var(--gold);">${profile.healthScore || 0}/100</div>
        </div>
        <div style="background:white;padding:8px;border-radius:6px;">
          <div style="font-size:10px;color:var(--ink-40);text-transform:uppercase;">Net Worth</div>
          <div style="font-weight:600;color:var(--ink);">₹${fmt((profile.mf || 0) + (profile.epf || 0) + (profile.fd || 0) + (profile.stocks || 0) + (profile.emergency || 0))}</div>
        </div>
        <div style="background:white;padding:8px;border-radius:6px;">
          <div style="font-size:10px;color:var(--ink-40);text-transform:uppercase;">Risk Profile</div>
          <div style="font-weight:600;color:var(--ink);text-transform:capitalize;">${profile.risk || 'Moderate'}</div>
        </div>
      </div>

      ${profile.income ? `
      <div style="margin-top:12px;">
        <div style="font-size:11px;font-weight:600;color:var(--ink-60);margin-bottom:6px;">Investments</div>
        <div style="display:flex;flex-wrap:wrap;gap:6px;">
          ${profile.mf ? `<span style="background:var(--gold-light);color:var(--gold);padding:4px 8px;border-radius:4px;font-size:11px;">MF: ₹${fmt(profile.mf)}</span>` : ''}
          ${profile.epf ? `<span style="background:var(--emerald-light);color:var(--emerald);padding:4px 8px;border-radius:4px;font-size:11px;">EPF: ₹${fmt(profile.epf)}</span>` : ''}
          ${profile.fd ? `<span style="background:var(--sky-light);color:var(--sky);padding:4px 8px;border-radius:4px;font-size:11px;">FD: ₹${fmt(profile.fd)}</span>` : ''}
          ${profile.stocks ? `<span style="background:var(--crimson-light);color:var(--crimson);padding:4px 8px;border-radius:4px;font-size:11px;">Stocks: ₹${fmt(profile.stocks)}</span>` : ''}
          ${profile.emergency ? `<span style="background:var(--ink-10);color:var(--ink-60);padding:4px 8px;border-radius:4px;font-size:11px;">Emergency: ₹${fmt(profile.emergency)}</span>` : ''}
        </div>
      </div>
      ` : ''}
    </div>

    <div style="font-size:11px;color:var(--ink-40);text-align:center;">
      Changes made locally will sync when you click "Sync Profile to Cloud"
    </div>`;

  container.querySelector('#profile-data').innerHTML = profileHtml;
}

async function loadUserProfile() {
  try {
    const result = await getUserProfile();
    if (result.success && result.profile) {
      // Load stored profile into UserState
      const profile = result.profile;
      UserState.update({
        name: profile.name || '',
        age: profile.age || 0,
        city: profile.city || '',
        risk: profile.risk || 'moderate',
        income: profile.income || 0,
        otherIncome: profile.otherIncome || 0,
        hra: profile.hra || 0,
        rentPaid: profile.rentPaid || 0,
        expRent: profile.expRent || 0,
        expGroceries: profile.expGroceries || 0,
        expTransport: profile.expTransport || 0,
        expFun: profile.expFun || 0,
        expOther: profile.expOther || 0,
        expEmi: profile.expEmi || 0,
        mf: profile.mf || 0,
        epf: profile.epf || 0,
        fd: profile.fd || 0,
        stocks: profile.stocks || 0,
        emergency: profile.emergency || 0,
        sip: profile.sip || 0,
        termCover: profile.termCover || 0,
        healthCover: profile.healthCover || 0,
        premium: profile.premium || 0,
        invested80c: profile.invested80c || 0,
        fireAge: profile.fireAge || 50,
        goal: profile.goal || 'fire',
        note: profile.note || '',
        healthScore: profile.healthScore || 0,
        ready: profile.name ? true : false
      });
    }
  } catch (err) {
    console.error('Failed to load user profile:', err);
  }
}

