     5→// ── Number Formatters ─────────────────────────────────────────────────────
     6→
     7→export function fmt(n) {
     8→  if (!n || isNaN(n)) return '0';
     9→  if (n >= 10000000) return (n / 10000000).toFixed(2) + 'Cr';
    10→  if (n >= 100000)   return (n / 100000).toFixed(1) + 'L';
    11→  if (n >= 1000)     return (n / 1000).toFixed(0) + 'K';
    12→  return Math.round(n).toString();
    13→}
    14→
    15→export function fmtRupee(n) {
    16→  return '₹' + fmt(n);
    17→}
    18→
    19→export function fmtCr(n) {
    20→  if (!n || isNaN(n)) return '₹0';
    21→  if (n >= 10000000) return '₹' + (n / 10000000).toFixed(2) + 'Cr';
    22→  if (n >= 100000)   return '₹' + (n / 100000).toFixed(1) + 'L';
    23→  return '₹' + fmt(n);
    24→}
    25→
    26→// ── AI Text Formatter ─────────────────────────────────────────────────────
    27→
    28→export function formatAI(text) {
    29→  if (!text) return '';
