    31→    .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
    32→    .replace(/\n\n/g, '</p><p>')
    33→    .replace(/\n(\d+\.)/g, '</p><p>$1')
    34→    .replace(/\n- /g, '</p><p>• ') + '</p>';
    35→}
