    45→      </div>
    46→      ${formatAI(content)}
    47→    </div>`;
    48→}
    49→
    50→// ── Score Calculators ─────────────────────────────────────────────────────
    51→
    52→export function calcEmergencyScore(U) {
    53→  const req = U.totalExpenses * 6;
    54→  return Math.min(100, Math.round((U.emergency / Math.max(1, req)) * 100));
    55→}
    56→
    57→export function calcInsuranceScore(U) {
    58→  const gap = Math.max(0, U.income * 10 - U.termCover);
    59→  return gap > 0
    60→    ? (U.healthCover > 300000 ? 40 : 20)
    61→    : (U.healthCover > 300000 ? 90 : 65);
    62→}
    63→
    64→export function calcInvestmentScore(U) {
    65→  const nw = U.netWorth;
    66→  return Math.min(100,
    67→    Math.round(((U.mf + U.stocks) / Math.max(1, nw)) * 100) + (U.sip > 0 ? 30 : 0)
    68→  );
    69→}
    70→
    71→export function calcDebtScore(U) {
    72→  return U.expEmi > 0
    73→    ? Math.max(20, 100 - Math.round((U.expEmi / Math.max(1, U.takeHome)) * 200))
    74→    : 95;
    75→}
    76→
    77→export function calcTaxScore(U) {
    78→  return Math.min(100,
    79→    Math.round((U.invested80c / 150000) * 60)
    80→    + (U.premium > 0 ? 20 : 0)
    81→    + (U.hra > 0 ? 20 : 0)
    82→  );
    83→}
    84→
    85→export function calcRetirementScore(U) {
