    87→    Math.round((U.netWorth / Math.max(1, U.income)) * 20) + (U.sip > 0 ? 40 : 0)
    88→  );
    89→}
    90→
    91→export function calcOverallScore(U) {
    92→  return Math.round((
    93→    calcEmergencyScore(U) +
    94→    calcInsuranceScore(U) +
    95→    Math.min(100, calcInvestmentScore(U)) +
    96→    calcDebtScore(U) +
    97→    calcTaxScore(U) +
    98→    calcRetirementScore(U)
    99→  ) / 6);
   100→}
