   102→// ── FIRE Math ─────────────────────────────────────────────────────────────
   103→
   104→export function calcRequiredSIP(target, annualReturn, months) {
   105→  const r = annualReturn / 12;
   106→  if (r === 0) return target / months;
   107→  return target * r / (Math.pow(1 + r, months) - 1);
   108→}
   109→
   110→// ── Tax Calculators ───────────────────────────────────────────────────────
   111→
   112→export function calcTaxOld(taxable) {
   113→  let tax = 0;
   114→  if (taxable <= 250000) return 0;
   115→  if (taxable <= 500000)   tax = (taxable - 250000) * 0.05;
   116→  else if (taxable <= 1000000) tax = 12500 + (taxable - 500000) * 0.20;
   117→  else tax = 112500 + (taxable - 1000000) * 0.30;
   118→  return Math.round(tax * 1.04);
   119→}
   120→
   121→export function calcTaxNew(taxable) {
   122→  let tax = 0;
   123→  if (taxable <= 300000) return 0;
   124→  if (taxable <= 700000)   tax = (taxable - 300000) * 0.05;
   125→  else if (taxable <= 1000000) tax = 20000 + (taxable - 700000) * 0.10;
   126→  else if (taxable <= 1200000) tax = 50000 + (taxable - 1000000) * 0.15;
   127→  else if (taxable <= 1500000) tax = 80000 + (taxable - 1200000) * 0.20;
   128→  else tax = 140000 + (taxable - 1500000) * 0.30;
   129→  return Math.round(tax * 1.04);
   130→}
