   144→        <circle cx="${cx}" cy="${cy}" r="${r}" fill="none" stroke="var(--surface-3)" stroke-width="9"/>
   145→        <circle cx="${cx}" cy="${cy}" r="${r}" fill="none" stroke="${color}" stroke-width="9"
   146→          stroke-dasharray="${circ.toFixed(1)}" stroke-dashoffset="${offset.toFixed(1)}" stroke-linecap="round"/>
   147→      </svg>
   148→      <div class="ring-center">
   149→        <div class="ring-num" style="color:${color};">${score}</div>
   150→        <div class="ring-lbl">${label}</div>
